### ReferenceLines and ReferenceAreas - Chart Markers and Highlights

Source: https://context7.com/recharts/recharts/llms.txt

Adds visual reference markers (horizontal and vertical lines) and highlighted regions to emphasize specific values or ranges in charts. ReferenceLine creates single-value indicators with optional labels and dash patterns, while ReferenceArea highlights ranges between x1/x2 or y1/y2 coordinates with customizable fill and stroke properties.

```jsx
import React from 'react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ReferenceLine, ReferenceArea, ResponsiveContainer } from 'recharts';

const data = [
  { name: 'Jan', value: 400 },
  { name: 'Feb', value: 300 },
  { name: 'Mar', value: 600 },
  { name: 'Apr', value: 800 },
  { name: 'May', value: 500 },
  { name: 'Jun', value: 700 },
];

function ReferenceExample() {
  return (
    <ResponsiveContainer width="100%" height={400}>
      <LineChart data={data} margin={{ top: 5, right: 30, left: 20, bottom: 5 }}>
        <CartesianGrid strokeDasharray="3 3" />
        <XAxis dataKey="name" />
        <YAxis />
        <Tooltip />

        {/* Horizontal reference line for average */}
        <ReferenceLine
          y={550}
          label="Average"
          stroke="red"
          strokeDasharray="3 3"
        />

        {/* Vertical reference line for specific month */}
        <ReferenceLine
          x="Mar"
          label="Q1 End"
          stroke="green"
        />

        {/* Reference area to highlight a range */}
        <ReferenceArea
          x1="Mar"
          x2="May"
          y1={300}
          y2={700}
          stroke="red"
          strokeOpacity={0.3}
          fill="red"
          fillOpacity={0.1}
          label="Critical Period"
        />

        <Line type="monotone" dataKey="value" stroke="#8884d8" />
      </LineChart>
    </ResponsiveContainer>
  );
}

export default ReferenceExample;
```

